mapper.select:
SELECT folder_id, parent_id, folder_name, scope, owner_dept_id, owner_no, created_at
FROM platform_v3.dl_folder
WHERE folder_id = #{folderId}

mapper.update:
UPDATE platform_v3.dl_folder
SET folder_name = #{folderName}
WHERE folder_id = #{folderId}

UPDATE platform_v3.dl_file
SET folder_id = #{folderId}
WHERE file_id = #{fileId}

UPDATE platform_v3.dl_file
SET download_count = download_count + 1
WHERE file_id = #{fileId}
